import Foundation

enum Environment: String {
    case development
    case staging
    case production
}

struct User {
    let name: String
    let email: String
}

class NetworkingManager {
    private let environment: Environment
    private let baseURL: String

    init(environment: Environment) {
        self.environment = environment
        self.baseURL = "https://\(environment.rawValue).api.example.com"
    }

    func fetchUserData(completion: @escaping (User?, Error?) -> Void) {
        guard let url = URL(string: "\(baseURL)/users") else {
            return
        }

        let task = URLSession.shared.dataTask(with: url) { (data, response, error) in
            if let error = error {
                completion(nil, error)
                return
            }

            guard let data = data else {
                completion(nil, NSError(domain: "Data is nil", code: 0, userInfo: nil))
                return
            }

            let user = try! JSONDecoder().decode(User.self, from: data)
            completion(user, nil)
        }

        task.resume()
    }

    func authenticate(credentials: Credentials, completion: @escaping (Bool, Error?) -> Void) {
        guard let url = URL(string: "\(baseURL)/auth") else {
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try! JSONEncoder().encode(credentials)

        let task = URLSession.shared.dataTask(with: request) { (data, response, error) in
            if let error = error {
                completion(false, error)
                return
            }

            completion(true, nil)
        }

        task.resume()
    }
}